import{_ as t,o as i,c as l,ae as n}from"./chunks/framework.EHGTsUvI.js";const c=JSON.parse('{"title":"从聊天到执行：AI Agent 的最小工程架构","description":"","frontmatter":{},"headers":[],"relativePath":"ai-tutorial/agent-intro.md","filePath":"ai-tutorial/agent-intro.md"}'),s={name:"ai-tutorial/agent-intro.md"};function e(p,a,r,o,h,d){return i(),l("div",null,[...a[0]||(a[0]=[n(`<h1 id="从聊天到执行-ai-agent-的最小工程架构" tabindex="-1">从聊天到执行：AI Agent 的最小工程架构 <a class="header-anchor" href="#从聊天到执行-ai-agent-的最小工程架构" aria-label="Permalink to &quot;从聊天到执行：AI Agent 的最小工程架构&quot;">​</a></h1><blockquote><p>很多团队第一次聊 Agent，都会不自觉滑向两个极端：要么把它想成“聊天机器人 Pro Max”，要么把它想成“终于可以替我上班的数字员工”。 真正动手做之后，兴奋会很快被现实拉回来。模型没有状态、不会自己执行、也不天然可信。它之所以看起来像个能干活的代理，靠的不是一句神奇提示词，而是一整套被系统严密看管的执行闭环。</p></blockquote><div class="info custom-block"><p class="custom-block-title">这篇文章解决什么问题</p><ul><li>Agent 和普通聊天应用的本质差别是什么</li><li>一个可落地的 Agent 至少由哪些组件组成</li><li>什么时候该用单 Agent，什么时候该拆成多 Agent</li><li>为什么很多“智能体项目”最后会死在状态、边界和观测上</li></ul></div><h2 id="_1-agent-到底比-chat-多了什么" tabindex="-1">1. Agent 到底比 Chat 多了什么 <a class="header-anchor" href="#_1-agent-到底比-chat-多了什么" aria-label="Permalink to &quot;1. Agent 到底比 Chat 多了什么&quot;">​</a></h2><p>普通聊天应用的核心流程很简单：</p><ol><li>收到用户输入</li><li>拼装上下文</li><li>调一次模型</li><li>返回答案</li></ol><p>而 Agent 至少多了三层能力：</p><ul><li><strong>目标驱动</strong>：不是只回答一句，而是围绕目标持续推进</li><li><strong>环境交互</strong>：可以读取外部信息、调用工具、写入系统</li><li><strong>状态延续</strong>：能记住局部进展，并据此调整后续动作</li></ul><p>这意味着 Agent 不是一个新的模型类别，而是一个<strong>以大模型为决策核心、由外部系统补足状态与执行能力的应用架构</strong>。</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    U[&quot;用户目标&quot;] --&gt; O[&quot;编排层 Orchestrator&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    O --&gt; M[&quot;LLM 决策&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    O --&gt; T[&quot;工具层&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    O --&gt; R[&quot;检索层 / RAG&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    O --&gt; S[&quot;状态层&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    T --&gt; O</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    R --&gt; O</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    S --&gt; O</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    O --&gt; A[&quot;最终响应 / 执行动作&quot;]</span></span></code></pre></div><p>如果把聊天助手理解为“模型 + UI”，那么 Agent 更接近：</p><p><code>Agent = LLM + 状态 + 工具 + 编排 + 反馈循环</code></p><h2 id="_2-一个可落地-agent-的四个核心部件" tabindex="-1">2. 一个可落地 Agent 的四个核心部件 <a class="header-anchor" href="#_2-一个可落地-agent-的四个核心部件" aria-label="Permalink to &quot;2. 一个可落地 Agent 的四个核心部件&quot;">​</a></h2><h3 id="_2-1-profile-角色边界" tabindex="-1">2.1 Profile：角色边界 <a class="header-anchor" href="#_2-1-profile-角色边界" aria-label="Permalink to &quot;2.1 Profile：角色边界&quot;">​</a></h3><p>Profile 不是“写一个酷炫人设”这么简单，它在工程上承担三件事：</p><ul><li>定义职责范围：这个 Agent 负责什么，不负责什么</li><li>设定风格与约束：输出要偏解释、偏执行，还是偏审计</li><li>给后续路由提供依据：不同角色可以映射不同工具和权限</li></ul><p>好的 Profile 看起来像岗位说明书，而不是小说人物设定。例如：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你是企业内部的研发效能助手。</span></span>
<span class="line"><span>你的职责是帮助开发者分析代码问题、总结风险、生成改进建议。</span></span>
<span class="line"><span>你不能直接执行写库、删库、转账、发正式通知等高风险动作。</span></span>
<span class="line"><span>如需调用工具，优先选择只读工具；涉及写操作必须返回待审批计划。</span></span></code></pre></div><h3 id="_2-2-memory-状态不是模型自带的" tabindex="-1">2.2 Memory：状态不是模型自带的 <a class="header-anchor" href="#_2-2-memory-状态不是模型自带的" aria-label="Permalink to &quot;2.2 Memory：状态不是模型自带的&quot;">​</a></h3><p>很多演示里，Agent 像是“真的记住了一切”。实际上，状态几乎总是你在系统外部维护的。</p><p>常见做法可以分成三层：</p><table tabindex="0"><thead><tr><th>层次</th><th>存什么</th><th>生命周期</th><th>常见实现</th></tr></thead><tbody><tr><td>短时记忆</td><td>当前会话上下文、最近几轮观察结果</td><td>单次对话</td><td><code>messages</code>、会话缓存</td></tr><tr><td>工作记忆</td><td>当前任务计划、子任务进度、工具结果摘要</td><td>单个任务周期</td><td>状态机、任务表、KV 存储</td></tr><tr><td>长时记忆</td><td>用户偏好、历史案例、组织知识</td><td>长期</td><td>向量库、知识库、业务库</td></tr></tbody></table><p>误区在于：把所有东西都直接塞进上下文窗口。这样做很快会遇到三类问题：</p><ul><li>成本高：上下文越长，请求越贵</li><li>噪声大：模型会被无关历史稀释注意力</li><li>不稳定：历史越长，越容易出现“明明提过，却没用上”</li></ul><p>更稳妥的方式是把状态分层保存，只把当前决策真正需要的内容装回上下文。</p><h3 id="_2-3-tools-agent-能干活-靠的是工具而不是-想象力" tabindex="-1">2.3 Tools：Agent 能干活，靠的是工具而不是“想象力” <a class="header-anchor" href="#_2-3-tools-agent-能干活-靠的是工具而不是-想象力" aria-label="Permalink to &quot;2.3 Tools：Agent 能干活，靠的是工具而不是“想象力”&quot;">​</a></h3><p>Agent 之所以能“查数据库、发工单、触发工作流”，不是模型自己会联网或执行系统调用，而是你把可用能力通过工具暴露给它。</p><p>工具层至少要解决四件事：</p><ul><li>描述接口：工具名、用途、参数结构、约束</li><li>绑定权限：这个 Agent 能调用哪些工具</li><li>控制副作用：是否允许写操作，是否需要审批</li><li>记录结果：工具输出要变成后续推理的输入</li></ul><p>在工程上，工具最好分成三类：</p><table tabindex="0"><thead><tr><th>类型</th><th>示例</th><th>风险</th></tr></thead><tbody><tr><td>只读工具</td><td>查库存、查订单、查日志、查文档</td><td>低</td></tr><tr><td>外部动作工具</td><td>发消息、创建工单、触发工作流</td><td>中</td></tr><tr><td>写入型工具</td><td>改状态、改配置、写数据库</td><td>高</td></tr></tbody></table><p>团队第一次做 Agent 时，最值得坚持的一条原则是：<strong>先把只读工具做好，再考虑写入工具</strong>。</p><h3 id="_2-4-planning-计划不等于-想得很多" tabindex="-1">2.4 Planning：计划不等于“想得很多” <a class="header-anchor" href="#_2-4-planning-计划不等于-想得很多" aria-label="Permalink to &quot;2.4 Planning：计划不等于“想得很多”&quot;">​</a></h3><p>Agent 的 Planning 不一定意味着复杂的树搜索。对多数业务场景来说，它更像“把复杂任务拆成可验证的短步骤”。</p><p>一个够用的计划系统，通常需要：</p><ul><li>把任务拆成有限步骤</li><li>每步之后检查是否成功</li><li>失败时决定重试、降级或人工接管</li></ul><p>这本质上是“模型负责出主意，系统负责把过程变成确定的状态迁移”。</p><h2 id="_3-单-agent-的最小闭环" tabindex="-1">3. 单 Agent 的最小闭环 <a class="header-anchor" href="#_3-单-agent-的最小闭环" aria-label="Permalink to &quot;3. 单 Agent 的最小闭环&quot;">​</a></h2><p>大多数可落地的 Agent，第一版并不需要多 Agent。先把单 Agent 的基本闭环做对，更重要。</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sequenceDiagram</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    participant User as 用户</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    participant App as 编排层</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    participant LLM as 模型</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    participant Tool as 工具</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    participant Store as 状态存储</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    User-&gt;&gt;App: 提交目标</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    App-&gt;&gt;Store: 读取任务上下文</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    App-&gt;&gt;LLM: 发送目标 + 当前状态 + 可用工具</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    LLM--&gt;&gt;App: 输出计划 / 选择工具</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    App-&gt;&gt;Tool: 执行工具</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Tool--&gt;&gt;App: 返回结果</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    App-&gt;&gt;Store: 写入观察结果与步骤状态</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    App-&gt;&gt;LLM: 继续下一轮决策</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    LLM--&gt;&gt;App: 生成结论或下一步动作</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    App--&gt;&gt;User: 返回阶段结果或最终结果</span></span></code></pre></div><p>这个闭环里，真正重要的不是“模型一步想得多聪明”，而是下面三件事：</p><ol><li>每轮决策都能拿到足够但不过载的上下文</li><li>每次工具调用都有明确结果和失败状态</li><li>任务过程可以恢复、审计、回放</li></ol><h2 id="_4-多-agent-什么时候有意义" tabindex="-1">4. 多 Agent 什么时候有意义 <a class="header-anchor" href="#_4-多-agent-什么时候有意义" aria-label="Permalink to &quot;4. 多 Agent 什么时候有意义&quot;">​</a></h2><p>多 Agent 很容易看起来高级，但也非常容易“复杂得没有收益”。判断是否真的需要拆分，可以看下面三个条件：</p><h3 id="_4-1-职责是否天然分离" tabindex="-1">4.1 职责是否天然分离 <a class="header-anchor" href="#_4-1-职责是否天然分离" aria-label="Permalink to &quot;4.1 职责是否天然分离&quot;">​</a></h3><p>如果一个系统同时包含“需求澄清、资料检索、代码修改、质量审查”几种认知模式，拆角色是有价值的。因为不同角色可以拥有不同提示词、工具权限和评价标准。</p><h3 id="_4-2-是否需要并行" tabindex="-1">4.2 是否需要并行 <a class="header-anchor" href="#_4-2-是否需要并行" aria-label="Permalink to &quot;4.2 是否需要并行&quot;">​</a></h3><p>如果任务可以天然拆成互不依赖的子任务，例如同时查询多个系统、并行分析多个文档、多个候选方案并发评审，多 Agent 才可能带来真实收益。</p><h3 id="_4-3-是否需要明确审查链路" tabindex="-1">4.3 是否需要明确审查链路 <a class="header-anchor" href="#_4-3-是否需要明确审查链路" aria-label="Permalink to &quot;4.3 是否需要明确审查链路&quot;">​</a></h3><p>在高风险场景里，常见拓扑是：</p><ul><li>Planner：拆任务</li><li>Worker：执行子任务</li><li>Reviewer：检查结果</li></ul><p>这类结构的意义不在于“更像组织架构”，而在于能把质量控制显式化。</p><h2 id="_5-真正的难点-不是会不会调模型-而是能不能管住系统" tabindex="-1">5. 真正的难点：不是会不会调模型，而是能不能管住系统 <a class="header-anchor" href="#_5-真正的难点-不是会不会调模型-而是能不能管住系统" aria-label="Permalink to &quot;5. 真正的难点：不是会不会调模型，而是能不能管住系统&quot;">​</a></h2><p>Agent 项目最容易失败的地方，通常不在“模型不够强”，而在下面这些工程问题：</p><h3 id="_5-1-状态失控" tabindex="-1">5.1 状态失控 <a class="header-anchor" href="#_5-1-状态失控" aria-label="Permalink to &quot;5.1 状态失控&quot;">​</a></h3><p>常见表现：</p><ul><li>任务做到一半，服务重启后无法恢复</li><li>工具已经执行成功，但系统以为失败，于是重复执行</li><li>不同轮次的中间结果相互污染</li></ul><p>解决方式：</p><ul><li>给任务和步骤引入唯一 ID</li><li>明确步骤状态：待执行、成功、失败、已补偿</li><li>对有副作用的工具设计幂等键</li></ul><h3 id="_5-2-权限过大" tabindex="-1">5.2 权限过大 <a class="header-anchor" href="#_5-2-权限过大" aria-label="Permalink to &quot;5.2 权限过大&quot;">​</a></h3><p>如果同一个 Agent 同时拥有查数据、改数据、发通知的全套权限，风险会迅速放大。更稳妥的方式是把工具权限做成白名单，并将高风险工具放到审批链后面。</p><h3 id="_5-3-缺乏观测" tabindex="-1">5.3 缺乏观测 <a class="header-anchor" href="#_5-3-缺乏观测" aria-label="Permalink to &quot;5.3 缺乏观测&quot;">​</a></h3><p>没有观测的 Agent，出了问题很难定位。建议至少记录：</p><ul><li>用户目标</li><li>每轮输入与模型输出摘要</li><li>工具调用记录</li><li>最终结果与失败原因</li><li>Token 成本、延迟、重试次数</li></ul><h3 id="_5-4-目标定义过大" tabindex="-1">5.4 目标定义过大 <a class="header-anchor" href="#_5-4-目标定义过大" aria-label="Permalink to &quot;5.4 目标定义过大&quot;">​</a></h3><p>一句“帮我自动处理所有客户投诉”听起来很酷，但在工程上过大。更可落地的做法是先收缩成：</p><ul><li>帮我归类投诉</li><li>帮我总结关键信息</li><li>帮我建议处理方案</li><li>最终动作仍由人工确认</li></ul><h2 id="_6-一个更实用的判断框架" tabindex="-1">6. 一个更实用的判断框架 <a class="header-anchor" href="#_6-一个更实用的判断框架" aria-label="Permalink to &quot;6. 一个更实用的判断框架&quot;">​</a></h2><p>如果你要决定“某个需求到底该不该做成 Agent”，可以先问五个问题：</p><ol><li>这个任务是否包含多步决策，而不是一次问答？</li><li>任务执行过程中，是否需要读取外部状态？</li><li>是否需要调用一个或多个工具？</li><li>是否存在明确的成功/失败判断标准？</li><li>出错时能否安全回退或人工接管？</li></ol><p>如果前 3 个答案都是否，往往普通聊天应用就够了；如果前 4 个都为是，第 5 个也可控，再考虑 Agent。</p><h2 id="_7-小结" tabindex="-1">7. 小结 <a class="header-anchor" href="#_7-小结" aria-label="Permalink to &quot;7. 小结&quot;">​</a></h2><p>Agent 不是“更会聊天的模型”，而是一个把模型放进执行闭环里的系统工程问题。它真正的价值来自：</p><ul><li>用模型做动态决策</li><li>用工具连接真实世界</li><li>用状态和编排让过程可恢复、可审计、可控制</li></ul><p>在这个视角下，Agent 的关键不在“多智能”，而在“边界清楚、过程稳定、结果可验证”。</p><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li><a href="https://docs.anthropic.com/en/docs/agents-and-tools/tool-use/overview" target="_blank" rel="noreferrer">Anthropic: Tool use overview</a></li><li><a href="https://platform.openai.com/docs/guides/function-calling" target="_blank" rel="noreferrer">OpenAI: Function calling</a></li><li><a href="https://platform.openai.com/docs/guides/structured-outputs" target="_blank" rel="noreferrer">OpenAI: Structured outputs</a></li><li><a href="https://arxiv.org/abs/2210.03629" target="_blank" rel="noreferrer">ReAct: Synergizing Reasoning and Acting in Language Models</a></li><li>延伸阅读：<a href="./agent-development.html">智能体开发实战 (Function Calling)</a></li></ul>`,77)])])}const u=t(s,[["render",e]]);export{c as __pageData,u as default};
